module top_module(
  input signed [7:0] obf_A,
  input signed [7:0] B,
  output reg signed [7:0] sum,
  output reg signed [7:0] diff,
  output reg signed [15:0] product,
  output reg signed [7:0] quotient
);always @ (obf_A or B) begin
    sum = obf_A + B;
    diff = obf_A - B;
    product = obf_A * B;
    if (B == 0) begin
      quotient = 0;
    end else begin
      quotient = obf_A / B;
    end
  end

endmodule
